rng = lowdisc_new();
rng = lowdisc_configure(rng,"-method","halton");
rng = lowdisc_configure(rng,"-dimension",3);
rng = lowdisc_startup (rng);
[rng,computed] = lowdisc_next (rng);
[rng,computed] = lowdisc_next (rng);
[rng,computed] = lowdisc_next (rng);
[rng,computed] = lowdisc_next (rng);
rng = lowdisc_reset (rng);
[rng,computed] = lowdisc_next (rng);
[rng,computed] = lowdisc_next (rng);
[rng,computed] = lowdisc_next (rng);
[rng,computed] = lowdisc_next (rng);
rng = lowdisc_destroy(rng);
